#include <bits/stdc++.h>
using namespace std;
const int INF=1000000000;
int cost[2001];
int main(){
    int n,t;
    cin>>n>>t;
    cost[0]=0;
    for(int i=1;i<=t;i++)cost[i]=INF;
    for(int i=0;i<n;i++){
    	int c,l;
    	cin>>c>>l;
    	for(int j=t;j>=0;j--)
    		cost[j]=min(cost[j],cost[max(j-l,0)]+c);
	}
	if(cost[t]==INF)cout<<"no solution";
	else cout<<cost[t];
    return 0;
}
